const lat = 49.71985822231634;
const lon = 17.221723412878973;
const r = await fetch(`https://nominatim.openstreetmap.org/reverse?format=jsonv2&lat=${lat}&lon=${lon}`).then(r => r.json());
return {
  display_name: r.display_name,
  address: r.address
}
